// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./interfaces/IFlashLoanReceiver.sol";
import "./interfaces/ILendingPool.sol";
import "./interfaces/ISwapRouter.sol";
import "./interfaces/ICurveStableSwap.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title FlashLoanArbitrageur
 * @notice Flash loan based arbitrage contract on Arbitrum
 * @dev Executes arbitrage between Uniswap and Curve using Aave flash loans
 */
contract FlashLoanArbitrageur is IFlashLoanReceiver, Ownable, ReentrancyGuard {
    ILendingPool private constant lendingPool = 
        ILendingPool(0x794a61358D6845594F94dc1DB02A252b5b4814aD); // Aave LendingPool on Arbitrum
    ISwapRouter private constant swapRouter = 
        ISwapRouter(0xE592427A0AEce92De3Edee1F18E0157C05861564); // Uniswap V3 Router on Arbitrum

    // Storage variables
    address public flashLoanToken;
    uint256 public flashLoanAmount;
    address public profitRecipient;
    
    // Events
    event FlashLoanExecuted(address indexed token, uint256 amount, uint256 profit);
    event ProfitExtracted(address indexed token, uint256 amount, address indexed recipient);
    event SwapExecuted(address indexed fromToken, address indexed toToken, uint256 fromAmount, uint256 toAmount);

    /**
     * @notice Initiates a flash loan for arbitrage
     * @param token The token to borrow
     * @param amount The amount to borrow
     * @param params Encoded arbitrage parameters
     */
    function initiateFlashLoan(
        address token,
        uint256 amount,
        bytes calldata params
    ) external onlyOwner nonReentrant {
        flashLoanToken = token;
        flashLoanAmount = amount;
        profitRecipient = owner();

        address[] memory assets = new address[](1);
        assets[0] = token;

        uint256[] memory amounts = new uint256[](1);
        amounts[0] = amount;

        uint256[] memory modes = new uint256[](1);
        modes[0] = 0; // No debt, must repay

        lendingPool.flashLoan(
            address(this),
            assets,
            amounts,
            modes,
            address(this),
            params,
            0
        );
    }

    /**
     * @notice Callback from Aave flash loan
     * @dev Executes arbitrage logic here
     */
    function executeOperation(
        address asset,
        uint256 amount,
        uint256 premium,
        address initiator,
        bytes calldata params
    ) external override returns (bytes32) {
        require(msg.sender == address(lendingPool), "FlashLoan: Invalid lender");
        require(initiator == address(this), "FlashLoan: Invalid initiator");

        (
            address tokenB,
            uint24 uniswapFee,
            address curvePool,
            int128 curveFromIndex,
            int128 curveToIndex,
            uint256 minAmountOut
        ) = abi.decode(params, (address, uint24, address, int128, int128, uint256));

        // Step 1: Swap on Uniswap (asset -> tokenB)
        uint256 amountB = _executeUniswapSwap(asset, tokenB, amount, uniswapFee);
        
        // Step 2: Swap on Curve (tokenB -> asset)
        uint256 amountRepay = _executeCurveSwap(tokenB, curvePool, curveFromIndex, curveToIndex, amountB);
        
        // Step 3: Check profit
        uint256 totalDue = amount + premium;
        require(amountRepay >= totalDue, "FlashLoan: Insufficient profit");
        
        // Step 4: Repay flash loan
        IERC20(asset).approve(address(lendingPool), totalDue);
        
        // Step 5: Send profit to owner
        uint256 profit = amountRepay - totalDue;
        if (profit > 0) {
            IERC20(asset).transfer(profitRecipient, profit);
            emit ProfitExtracted(asset, profit, profitRecipient);
        }

        emit FlashLoanExecuted(asset, amount, profit);
        
        return keccak256("ERC3156FlashBorrower.onFlashLoan");
    }

    /**
     * @notice Executes a swap on Uniswap V3
     * @param tokenIn Input token
     * @param tokenOut Output token
     * @param amountIn Input amount
     * @param fee Uniswap pool fee
     * @return amountOut Output amount
     */
    function _executeUniswapSwap(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint24 fee
    ) internal returns (uint256 amountOut) {
        IERC20(tokenIn).approve(address(swapRouter), amountIn);

        ISwapRouter.ExactInputSingleParams memory params = ISwapRouter.ExactInputSingleParams({
            tokenIn: tokenIn,
            tokenOut: tokenOut,
            fee: fee,
            recipient: address(this),
            deadline: block.timestamp + 60,
            amountIn: amountIn,
            amountOutMinimum: 0,
            sqrtPriceLimitX96: 0
        });

        amountOut = swapRouter.exactInputSingle(params);
        emit SwapExecuted(tokenIn, tokenOut, amountIn, amountOut);
    }

    /**
     * @notice Executes a swap on Curve Finance
     * @param tokenIn Input token
     * @param curvePool Curve pool address
     * @param fromIndex Token index in pool
     * @param toIndex Token index in pool
     * @param amountIn Input amount
     * @return amountOut Output amount
     */
    function _executeCurveSwap(
        address tokenIn,
        address curvePool,
        int128 fromIndex,
        int128 toIndex,
        uint256 amountIn
    ) internal returns (uint256 amountOut) {
        IERC20(tokenIn).approve(curvePool, amountIn);

        ICurveStableSwap curveInterface = ICurveStableSwap(curvePool);
        amountOut = curveInterface.exchange(fromIndex, toIndex, amountIn, 0);
        
        emit SwapExecuted(tokenIn, address(0), amountIn, amountOut);
    }

    /**
     * @notice Allows owner to recover tokens
     */
    function recoverToken(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner(), amount);
    }

    /**
     * @notice Returns address provider of Aave lending pool
     */
    function ADDRESSES_PROVIDER() public pure returns (address) {
        return 0xa97684ead0e402dC232d5A977953DF7ECBaB3CDb; // Aave address provider on Arbitrum
    }

    /**
     * @notice Returns lending pool
     */
    function LENDING_POOL() public pure override returns (address) {
        return 0x794a61358D6845594F94dc1DB02A252b5b4814aD;
    }

    // Required for IFlashLoanReceiver
    receive() external payable {}
}

